package org.example.spring_data_jpa_handson.Exercise03;

/*
 * Exercise 3: Hibernate Annotation Configuration
 *
 * This exercise explains annotation-based Hibernate configuration.
 *
 * Important Annotations:
 * 1. @Entity
 * 2. @Table
 * 3. @Id
 * 4. @GeneratedValue
 * 5. @Column
 *
 * Hibernate Configuration:
 * - Dialect
 * - Driver
 * - Connection URL
 * - Username
 * - Password
 */

public class HibernateAnnotationConfiguration {

    public static void main(String[] args) {

        System.out.println("Exercise 3 - Hibernate Annotation Configuration");
        System.out.println("-----------------------------------------------");

        System.out.println("Annotations Used:");
        System.out.println("@Entity");
        System.out.println("@Table");
        System.out.println("@Id");
        System.out.println("@GeneratedValue");
        System.out.println("@Column");

        System.out.println("\nHibernate Configuration:");
        System.out.println("Dialect");
        System.out.println("Driver");
        System.out.println("Connection URL");
        System.out.println("Username");
        System.out.println("Password");
    }
}